arguments.new_str:
using Microsoft.ML;
using Microsoft.ML.Data;
using Microsoft.Extensions.ML;

// --- Data model classes ---

public class CustomerData
{
    [LoadColumn(0)] public float Age { get; set; }
    [LoadColumn(1)] public float Income { get; set; }
    [LoadColumn(2)] public string Region { get; set; } = string.Empty;
    [LoadColumn(3)] public float PurchaseHistory { get; set; }
    [LoadColumn(4), ColumnName("Label")] public bool Churned { get; set; }
}

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")] public bool Churned { get; set; }
    public float Probability { get; set; }
    public float Score { get; set; }
}

// --- Train the model and register services ---

var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");

var dataView = mlContext.Data.LoadFromTextFile<CustomerData>(
    dataPath, hasHeader: true, separatorChar: ',');

var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2, seed: 42);

var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region")
    .Append(mlContext.Transforms.Concatenate("Features", "Age", "Income", "PurchaseHistory", "RegionEncoded"))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
        labelColumnName: "Label", featureColumnName: "Features"));

Console.WriteLine("Training churn prediction model...");
var model = pipeline.Fit(split.TrainSet);

var predictions = model.Transform(split.TestSet);
var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");

Console.WriteLine($"Model metrics:");
Console.WriteLine($"  Accuracy:  {metrics.Accuracy:F4}");
Console.WriteLine($"  AUC:       {metrics.AreaUnderRocCurve:F4}");
Console.WriteLine($"  F1 Score:  {metrics.F1Score:F4}");

var modelPath = Path.Combine(AppContext.BaseDirectory, "churn_model.zip");
mlContext.Model.Save(model, split.TrainSet.Schema, modelPath);
Console.WriteLine($"Model saved to {modelPath}");

// --- Configure web application ---

var builder = WebApplication.CreateBuilder(args);

builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API — POST /predict with { age, income, region, purchaseHistory }");

app.MapPost("/predict", (
    PredictionEnginePool<CustomerData, ChurnPrediction> predictionPool,
    CustomerPredictRequest request) =>
{
    var input = new CustomerData
    {
        Age = request.Age,
        Income = request.Income,
        Region = request.Region,
        PurchaseHistory = request.PurchaseHistory
    };

    var prediction = predictionPool.Predict(input);

    return Results.Ok(new
    {
        churned = prediction.Churned,
        probability = prediction.Probability,
        score = prediction.Score
    });
});

app.Run();

public record CustomerPredictRequest(float Age, float Income, string Region, float PurchaseHistory);

