 app.MapGet("/", () => "Churn Predictor API — POST /predict with { age, income, region, purchaseHistory }");

 app.MapPost("/predict", (
     PredictionEnginePool<CustomerData, ChurnPrediction> predictionPool,
     CustomerPredictRequest request) =>
 {
     var input = new CustomerData
     {
         Age = request.Age,
         Income = request.Income,
         Region = request.Region,
         PurchaseHistory = request.PurchaseHistory
     };

     var prediction = predictionPool.Predict(input);

     return Results.Ok(new
     {
         churned = prediction.Churned,
         probability = prediction.Probability,
         score = prediction.Score
     });
 });

 app.Run();

 public record CustomerPredictRequest(float Age, float Income, string Region, float PurchaseHistory);

