1. using Microsoft.ML;
2. using Microsoft.ML.Data;
3. using Microsoft.Extensions.ML;
4. 
5. // --- Train the model ---
6. 
7. var mlContext = new MLContext(seed: 42);
8. var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");
9. 
10. var dataView = mlContext.Data.LoadFromTextFile<CustomerData>(
11.     dataPath, hasHeader: true, separatorChar: ',');
12. 
13. var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2, seed: 42);
14. 
15. var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region")
16.     .Append(mlContext.Transforms.Concatenate("Features", "Age", "Income", "PurchaseHistory", "RegionEncoded"))
17.     .Append(mlContext.Transforms.NormalizeMinMax("Features"))
18.     .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
19.         labelColumnName: "Label", featureColumnName: "Features"));
20. 
21. Console.WriteLine("Training churn prediction model...");
22. var model = pipeline.Fit(split.TrainSet);
23. 
24. // Evaluate on test set — requires both positive and negative examples
25. try
26. {
27.     var testPredictions = model.Transform(split.TestSet);
28.     var metrics = mlContext.BinaryClassification.Evaluate(testPredictions, labelColumnName: "Label");
29.     Console.WriteLine($"Model metrics (test set):");
30.     Console.WriteLine($"  Accuracy:  {metrics.Accuracy:F4}");
31.     Console.WriteLine($"  AUC:       {metrics.AreaUnderRocCurve:F4}");
32.     Console.WriteLine($"  F1 Score:  {metrics.F1Score:F4}");
33. }
34. catch (ArgumentOutOfRangeException)
35. {
36.     Console.WriteLine("Note: Dataset too small for reliable evaluation metrics. Add more rows for proper train/test evaluation.");
37. }
38. 
39. var modelPath = Path.Combine(AppContext.BaseDirectory, "churn_model.zip");
40. mlContext.Model.Save(model, split.TrainSet.Schema, modelPath);
41. Console.WriteLine($"Model saved to {modelPath}");
42. 
43. // --- Configure web application ---
44. 
45. var builder = WebApplication.CreateBuilder(args);
46. 
47. builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
48.     .FromFile(modelPath);
49. 
50. var app = builder.Build();
51. 
52. app.MapGet("/", () => "Churn Predictor API — POST /predict with { age, income, region, purchaseHistory }");
53. 
54. app.MapPost("/predict", (
55.     PredictionEnginePool<CustomerData, ChurnPrediction> predictionPool,
56.     CustomerPredictRequest request) =>
57. {
58.     var input = new CustomerData
59.     {
60.         Age = request.Age,
61.         Income = request.Income,
62.         Region = request.Region,
63.         PurchaseHistory = request.PurchaseHistory
64.     };
65. 
66.     var prediction = predictionPool.Predict(input);
67. 
68.     return Results.Ok(new
69.     {
70.         churned = prediction.Churned,
71.         probability = prediction.Probability,
72.         score = prediction.Score
73.     });
74. });
75. 
76. app.Run();
77. 
78. // --- Data model classes ---
79. 
80. public record CustomerPredictRequest(float Age, float Income, string Region, float PurchaseHistory);
81. 
82. public class CustomerData
83. {
84.     [LoadColumn(0)] public float Age { get; set; }
85.     [LoadColumn(1)] public float Income { get; set; }
86.     [LoadColumn(2)] public string Region { get; set; } = string.Empty;
87.     [LoadColumn(3)] public float PurchaseHistory { get; set; }
88.     [LoadColumn(4), ColumnName("Label")] public bool Churned { get; set; }
89. }
90. 
91. public class ChurnPrediction
92. {
93.     [ColumnName("PredictedLabel")] public bool Churned { get; set; }
94.     public float Probability { get; set; }
95.     public float Score { get; set; }
96. }
